import{_ as a,o as t,c as o,a3 as r}from"./chunks/framework.CjquFG0V.js";const y=JSON.parse('{"title":"28. Salary Packaging","description":"","frontmatter":{"title":"28. Salary Packaging","eba":"Nurses and Midwives 2024-2028","topics":["wages","salary-packaging"]},"headers":[],"relativePath":"ebas/nurses-midwives/wages/28-salary-packaging.md","filePath":"ebas/nurses-midwives/wages/28-salary-packaging.md"}'),s={name:"ebas/nurses-midwives/wages/28-salary-packaging.md"};function n(i,e,l,p,c,g){return t(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="_28-salary-packaging" tabindex="-1">28. Salary Packaging <a class="header-anchor" href="#_28-salary-packaging" aria-label="Permalink to &quot;28. Salary Packaging&quot;">​</a></h1><p><strong>28.1</strong> An Employee may elect to salary package the current salary specified in <a href="/eba/ebas/nurses-midwives/appendices/02-wages-and-allowances.html">Appendix 2</a> in accordance with the Employer&#39;s policy.</p><p><strong>28.2</strong> The Employee will compensate the Employer from within their salary, for any Fringe Benefits Tax (FBT) incurred as a consequence of the Employee&#39;s salary packaging arrangement. Where the Employee chooses not to pay any of the costs associated with their salary packaging, the Employer may cease the Employee&#39;s salary packaging arrangements.</p><p><strong>28.3</strong> The Employee may elect to convert the amount packaged to salary for any reason, including where salary packaging ceases to be an advantage to the Employee because of subsequent changes to FBT legislation. Any costs associated with the conversion to salary will be borne by the Employee and the Employer will not be liable to make up any benefit lost as a consequence of an Employee&#39;s decision to convert to salary.</p><p><strong>28.4</strong> From 24 June 2024, where an overpayment to the salary packaging provider occurs as a result of Employer error, the Employer will refund the overpayment to the Employee and recover the money from the provider. Where all or part of the overpayment is subsequently refunded to the Employee by the provider, the Employer and Employee will take all reasonable steps to reach agreement on an appropriate resolution to:</p><p><strong>(a)</strong> address the repayment being made more than once; and</p><p><strong>(b)</strong> ensure that the Employee is neither advantaged nor disadvantaged as a result of the overpayment,</p><p>provided that if agreement cannot be reached, the matter will be resolved in accordance with <a href="/eba/ebas/nurses-midwives/consultation-disputes/13-dispute-resolution-procedure.html">clause 13</a> (Dispute Resolution Procedure).</p><p><strong>28.5</strong> The Employee will be responsible for all costs associated with the administration of their salary packaging arrangements, provided that such costs will be confined to reasonable commercial charges as levied directly by the external salary packaging provider and/or in- house payroll service (as applicable), as varied from time to time.</p><p><strong>28.6</strong> Employees who are considering salary packaging should seek independent financial advice. The Employer will not be responsible for the cost or outcome of any such advice.</p><p><strong>28.7</strong> Superannuation contributions paid by the Employer into an approved fund will be calculated on the Employee&#39;s pre-packaged rate of pay.</p><p>Plain language terms: salary sacrifice, packaging, novated lease.</p>',12)])])}const h=a(s,[["render",n]]);export{y as __pageData,h as default};
